A debounce function delays the execution of a function until after a specified wait time has passed since the last time it was called.

```javascript
function debounce(func, wait) {
  let timeout;
  return function executedFunction(...args) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

// Example usage: Debouncing search input
const searchInput = document.getElementById('search');
const updateResults = () => console.log('Fetching results for:', searchInput.value);

const debouncedSearch = debounce(updateResults, 300);
searchInput.addEventListener('input', debouncedSearch);
```
